"""matplotlib.axes._axes — Axes class stub."""

from matplotlib.artist import Artist


class Axes(Artist):
    """Stub Axes class for direct import compatibility."""

    name = 'rectilinear'

    def __init__(self, fig=None, rect=None, **kwargs):
        super().__init__()
        self.figure = fig
        self._position = rect
        self.patch = None
        self.dataLim = None
        self.viewLim = None
        self.transData = None
        self.transAxes = None

    # Plotting methods (stubs — real plotting goes through pyplot)
    def plot(self, *args, **kwargs): return []
    def scatter(self, *args, **kwargs): return None
    def bar(self, *args, **kwargs): return None
    def barh(self, *args, **kwargs): return None
    def hist(self, *args, **kwargs): return ([], [], [])
    def pie(self, *args, **kwargs): return ([], [])
    def imshow(self, *args, **kwargs): return None
    def contour(self, *args, **kwargs): return None
    def contourf(self, *args, **kwargs): return None
    def pcolormesh(self, *args, **kwargs): return None
    def fill(self, *args, **kwargs): return []
    def fill_between(self, *args, **kwargs): return None
    def fill_betweenx(self, *args, **kwargs): return None
    def errorbar(self, *args, **kwargs): return None
    def boxplot(self, *args, **kwargs): return {}
    def violinplot(self, *args, **kwargs): return {}
    def stem(self, *args, **kwargs): return None
    def step(self, *args, **kwargs): return []
    def stackplot(self, *args, **kwargs): return []
    def streamplot(self, *args, **kwargs): return None
    def quiver(self, *args, **kwargs): return None
    def hexbin(self, *args, **kwargs): return None
    def matshow(self, *args, **kwargs): return None
    def spy(self, *args, **kwargs): return None
    def tripcolor(self, *args, **kwargs): return None
    def tricontour(self, *args, **kwargs): return None
    def tricontourf(self, *args, **kwargs): return None
    def triplot(self, *args, **kwargs): return []

    # Axis config
    def set_xlabel(self, label, **kwargs): pass
    def set_ylabel(self, label, **kwargs): pass
    def set_zlabel(self, label, **kwargs): pass
    def set_title(self, label, **kwargs): pass
    def set_xlim(self, *args, **kwargs): return (0, 1)
    def set_ylim(self, *args, **kwargs): return (0, 1)
    def set_zlim(self, *args, **kwargs): return (0, 1)
    def get_xlim(self): return (0, 1)
    def get_ylim(self): return (0, 1)
    def set_xscale(self, scale, **kwargs): pass
    def set_yscale(self, scale, **kwargs): pass
    def set_aspect(self, aspect, **kwargs): pass
    def set_xticks(self, ticks, labels=None, **kwargs): pass
    def set_yticks(self, ticks, labels=None, **kwargs): pass
    def get_xticks(self): return []
    def get_yticks(self): return []
    def set_xticklabels(self, labels, **kwargs): pass
    def set_yticklabels(self, labels, **kwargs): pass
    def tick_params(self, **kwargs): pass
    def grid(self, visible=None, which='major', axis='both', **kwargs): pass
    def legend(self, *args, **kwargs): return None
    def axhline(self, y=0, **kwargs): return None
    def axvline(self, x=0, **kwargs): return None
    def axhspan(self, ymin, ymax, **kwargs): return None
    def axvspan(self, xmin, xmax, **kwargs): return None
    def text(self, x, y, s, **kwargs): return None
    def annotate(self, text, xy, **kwargs): return None
    def arrow(self, x, y, dx, dy, **kwargs): return None
    def set_facecolor(self, c): pass
    def set_axis_off(self): pass
    def set_axis_on(self): pass
    def invert_xaxis(self): pass
    def invert_yaxis(self): pass
    def twinx(self): return Axes(self.figure)
    def twiny(self): return Axes(self.figure)
    def add_patch(self, p): return p
    def add_artist(self, a): return a
    def add_collection(self, c): return c
    def add_line(self, line): return line
    def clear(self): pass
    def cla(self): pass
    def relim(self): pass
    def autoscale_view(self, tight=None, scalex=True, scaley=True): pass
    def margins(self, *args, **kwargs): pass
    def set_position(self, pos, which='both'): pass
    def get_position(self, original=False): return None
    def get_legend(self): return None
    def get_xaxis(self): return None
    def get_yaxis(self): return None
    def view_init(self, elev=None, azim=None): pass
    def set_box_aspect(self, aspect): pass
    def indicate_inset_zoom(self, inset_ax, **kwargs): return None
    def indicate_inset(self, bounds, inset_ax=None, **kwargs): return None
    def add_subplot(self, *args, **kwargs): return Axes(self.figure)
    def colorbar(self, mappable, **kwargs): return None

    @property
    def spines(self):
        return type('Spines', (), {
            '__getitem__': lambda s, k: type('S', (), {
                'set_visible': lambda s2, v: None,
                'set_color': lambda s2, c: None,
                'set_linewidth': lambda s2, w: None,
                'set_position': lambda s2, p: None,
            })(),
            'values': lambda s: [],
        })()

    @property
    def xaxis(self):
        return type('XAxis', (), {
            'set_visible': lambda s, v: None,
            'set_major_formatter': lambda s, f: None,
            'set_minor_formatter': lambda s, f: None,
            'set_major_locator': lambda s, l: None,
            'set_minor_locator': lambda s, l: None,
            'set_ticks_position': lambda s, p: None,
            'set_label_position': lambda s, p: None,
        })()

    @property
    def yaxis(self):
        return type('YAxis', (), {
            'set_visible': lambda s, v: None,
            'set_major_formatter': lambda s, f: None,
            'set_minor_formatter': lambda s, f: None,
            'set_major_locator': lambda s, l: None,
            'set_minor_locator': lambda s, l: None,
            'set_ticks_position': lambda s, p: None,
            'set_label_position': lambda s, p: None,
        })()

    @property
    def flat(self):
        return [self]


class SubplotBase:
    pass

Subplot = Axes
